INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Multi-protocol client$q$, $q$Test REST, GraphQL, WebSocket, Server-Sent Events, and gRPC APIs from one native desktop application.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Git Sync$q$, $q$Sync API collections and environments directly to a Git repository for version control and pull-request-style review.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Design-first OpenAPI support$q$, $q$Author, lint, and preview OpenAPI specifications and generate mock servers directly from them.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Environment and variable management$q$, $q$Nested, environment-scoped variables and template tags support complex, multi-step, or chained API workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Mock servers$q$, $q$Spin up mock API responses so frontend and backend teams can build in parallel before an API is finished.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Inso CLI$q$, $q$Run collections, tests, and OpenAPI lint checks headlessly inside CI/CD pipelines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Role-based access control and SSO$q$, $q$Pro and Enterprise plans add RBAC, SAML/OIDC single sign-on, and SCIM provisioning for larger teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Secrets vault integrations$q$, $q$Enterprise plan connects natively to AWS, GCP, HashiCorp Vault, and Azure Key Vault for centralized credential management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Clean, uncluttered interface that many users find easier to learn than Postman$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Native Git-based version control for API collections, not bolted on as an add-on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Generous free tier with no seat-based paywall for core testing features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Strong first-class support for GraphQL and gRPC alongside REST$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Backed by Kong's ongoing open-source maintenance and enterprise infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Performance can slow down noticeably with very large collections$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Fewer built-in automated monitoring and test-reporting features than Postman$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Some collaboration and mock-server capacity is gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Enterprise SSO and SCIM require the most expensive plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Smaller third-party plugin and integration marketplace than more established competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Is Insomnia free to use?$q$, $q$Yes. The Essentials plan is free and includes unlimited local and cloud projects, Git Sync for up to three users, the Inso CLI, and 1,000 mock-server requests per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Is Insomnia open source?$q$, $q$Yes. Insomnia's core client is open source and maintained publicly on GitHub under the Kong organization, even after Kong Inc. acquired the project in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Who owns Insomnia?$q$, $q$Insomnia is owned and maintained by Kong Inc., the API gateway and service-connectivity company headquartered in San Francisco, which acquired the project from original creator Gregory Schier in October 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Does Insomnia support GraphQL and gRPC?$q$, $q$Yes. Insomnia natively supports REST, GraphQL, WebSocket, Server-Sent Events, and gRPC in the same client, unlike many tools that only add GraphQL or gRPC support as a plugin.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$How does Insomnia compare to Postman?$q$, $q$Insomnia is generally seen as simpler and cheaper per seat, with native Git-based collaboration, while Postman offers a larger integration marketplace and more built-in automated testing and monitoring tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Does Insomnia have a mobile app?$q$, $q$No. Insomnia is a desktop application available for macOS, Windows, and Linux; there is no dedicated iOS or Android app.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$API design and debugging$q$, $q$Backend developers build, inspect, and debug REST and GraphQL requests during day-to-day development.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$QA and API test automation$q$, $q$QA teams validate endpoint behavior and run regression checks against staging and production APIs.$q$, $q$QA engineers and test automation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$CI/CD API testing$q$, $q$DevOps teams run Insomnia collections and OpenAPI lint checks automatically on every pull request using the Inso CLI.$q$, $q$DevOps and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Essentials$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Unlimited local and cloud projects for all users","Git Sync for up to 3 users","Inso CLI for CI/CD","1,000 mock-server requests per month","End-to-end encryption"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Pro$q$, $q$$12/user/month$q$, $q$monthly (15% off annually)$q$, NULL, $q$["Unlimited users on Git Sync","Unlimited organizations","Role-based access control","10,000 mock-server requests per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$Enterprise$q$, $q$$45/user/month$q$, $q$monthly, self-serve up to 50 users$q$, NULL, $q$["Native Kong Konnect integration","SAML/OIDC SSO and SCIM","Vault integrations (AWS, GCP, HashiCorp, Azure)","Unlimited mock-server requests"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Insomnia began in 2015 as an independent, design-focused REST client built by developer Gregory Schier, and it grew into one of the most widely used open-source API tools before Kong Inc. acquired it in October 2019. Kong, the API gateway and service-connectivity company founded out of the earlier Mashape marketplace, uses Insomnia as the client-side counterpart to its Kong Studio and Kong Konnect products while keeping the core client open source on GitHub.$q$, $q$The application is a native desktop client for macOS, Windows, and Linux that supports REST, GraphQL, WebSocket, Server-Sent Events, and gRPC in a single window, which sets it apart from tools that bolt on GraphQL or gRPC support as an afterthought. Collections can live locally, sync through Insomnia Cloud, or sync directly to a Git repository, letting engineering teams version-control API requests the same way they version-control application code.$q$, $q$Because the free tier already includes unlimited cloud and local projects, Git Sync for small teams, and a functioning mock server, Insomnia is commonly adopted first by individual developers or small teams and later upgraded to Pro or Enterprise as organizations need shared workspaces, RBAC, or SSO.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Insomnia's request builder supports environment and sub-environment variables, template tags, pre-request and post-response scripting, and reusable authentication configurations, which makes it practical for testing complex, multi-step API flows such as OAuth handshakes or chained requests that depend on earlier responses.$q$, $q$Design-first teams can author and lint OpenAPI specifications directly inside Insomnia and generate mock servers from those specs, allowing frontend and backend teams to build in parallel against a simulated API before the real implementation exists. The Inso CLI extends this into CI/CD, running collection tests, lint checks, and spec validation automatically on every pull request.$q$, $q$Collaboration features scale with plan tier: Git Sync brings pull-request-style review to API collections, while Pro and Enterprise add unlimited organizations, role-based access control, enterprise SSO/SCIM, and native secrets-vault integrations with AWS, GCP, HashiCorp Vault, and Azure Key Vault for teams that need centralized credential management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Insomnia uses a three-tier, per-user pricing model. The free Essentials plan is unusually generous for a developer tool, offering unlimited local and cloud projects for all users, Git Sync for up to three collaborators, the Inso CLI, and 1,000 free mock-server requests per month, with no feature-limited trial period required.$q$, $q$Pro costs 12 dollars per user per month and removes the Git Sync collaborator cap, adds unlimited organizations and role-based access control, and raises the mock-request allowance to 10,000 per month. Enterprise starts at 45 dollars per user per month (self-serve up to 50 seats, with custom contracts above that) and adds native Kong Konnect integration, SAML/OIDC SSO, SCIM provisioning, storage-location controls, and unlimited mock requests, positioning Insomnia as noticeably cheaper than Postman's equivalent team tiers for comparably sized groups.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
