INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26e0091a-2dbf-4bce-9fd3-e6410e5065db', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Fully modular architecture$q$, $q$Enable only the modules a network needs, from authentication to filtering to protocol extensions, without patching core code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$IRCv3 compliance$q$, $q$Supports all ratified IRCv3 specifications for compatibility with modern IRC clients and bouncers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$SSL/TLS support$q$, $q$Encrypted connections via both GnuTLS and OpenSSL, selectable per deployment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$WebSocket support$q$, $q$Native module for accepting WebSocket connections, enabling browser-based IRC clients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$High-performance connection handling$q$, $q$Linux epoll and FreeBSD kqueue support allow efficient handling of large numbers of simultaneous connections.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Granular oper permissions$q$, $q$Abstract operator classes let administrators assign fine-grained rights to different staff roles.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Modern password hashing$q$, $q$Built-in bcrypt and PBKDF2 support for secure account and oper password storage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Cross-platform support$q$, $q$Runs on Linux, BSD, Windows, and macOS, unlike many IRCd projects that target UNIX-like systems only.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Extensive, well-documented module system for customizing server behavior$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Full IRCv3 protocol support keeps it compatible with modern clients$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Strong performance at scale thanks to epoll/kqueue support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Rare native Windows support alongside Linux, BSD, and macOS$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Requires self-hosting and server administration knowledge; no managed hosting offered by the project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$No official commercial support contracts, only community and documentation-based help$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Initial setup and module configuration has a learning curve for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$IRC as a protocol has a smaller mainstream user base than modern chat platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$C++ codebase means custom module development requires programming expertise$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Is InspIRCd free?$q$, $q$Yes. InspIRCd is completely free and open source under the GNU General Public License v2, with no paid tiers or subscription costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$What operating systems does InspIRCd support?$q$, $q$InspIRCd runs on Linux, BSD, Windows, and macOS, which is broader platform coverage than most other IRCd projects offer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Who maintains InspIRCd?$q$, $q$InspIRCd is maintained by the InspIRCd Contributors, a volunteer open-source community, with development tracing back to around 2002 when it was started by Craig Edwards, Craig McLure, and Robin Burchell.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Does InspIRCd support modern IRC features?$q$, $q$Yes. InspIRCd implements all ratified IRCv3 specifications along with WebSocket support, making it compatible with modern IRC clients and browser-based chat interfaces.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$How is InspIRCd different from UnrealIRCd?$q$, $q$InspIRCd was written entirely from scratch in C++ rather than evolving from an older codebase, giving it a more modular architecture, while UnrealIRCd has a longer history dating to 1999 with its own large user base.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Do I need to host InspIRCd myself?$q$, $q$Yes. InspIRCd is self-hosted server software; there is no official managed or SaaS hosting option from the project itself, though many VPS providers can run it.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Community IRC networks$q$, $q$Operators run InspIRCd to host public or private IRC networks for hobbyist, gaming, or developer communities.$q$, $q$IRC network operators and community administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Developer and open-source project chat$q$, $q$Open-source projects run InspIRCd instances for real-time contributor and support chat alongside modern platforms.$q$, $q$Open-source maintainers and developer communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$University and institutional chat infrastructure$q$, $q$Universities and technical organizations self-host InspIRCd for internal or research-community communication.$q$, $q$IT departments and academic institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$Open Source$q$, $q$Free$q$, $q$one-time (self-hosted)$q$, NULL, $q$["Full server source code under GPLv2","All core and optional modules included","Community documentation and support","No usage limits or license fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InspIRCd is a free, open-source IRC server (IRCd) written from scratch in C++, originally developed by Craig Edwards, Craig McLure, and Robin Burchell starting around 2002 as an alternative to the aging codebases of established IRC daemons. Rather than forking an existing server, the team built InspIRCd as a clean implementation, which let them design a modular architecture and avoid inherited technical debt from earlier projects like ircd-hybrid or the Unreal lineage.$q$, $q$The project has no corporate owner; it is licensed under the GNU General Public License v2 and maintained by the InspIRCd Contributors community on GitHub, with a public, structured release cadence that has continued for over two decades, including the current 4.x stable series.$q$, $q$InspIRCd runs on Linux, BSD, Windows, and macOS, and is used to power more than 1,000 IRC networks worldwide, including community networks such as Snoonet and Teranova, making it one of the most widely deployed independent IRCd implementations alongside UnrealIRCd and the charybdis/solanum family used by large public networks.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$InspIRCd's core design principle is modularity: server operators compile or load only the modules they need, keeping deployments lightweight and reducing attack surface compared to monolithic IRCd designs. It supports SSL/TLS via both GnuTLS and OpenSSL, WebSocket connections for browser-based IRC clients, and the HAProxy PROXY protocol for operators running the server behind a load balancer or reverse proxy.$q$, $q$Security and authentication features include bcrypt and PBKDF2 password hashing, abstract operator classes with granular, per-role permissions, a regular-expression-based spam filter, and UNIX socket support for local connections. On the protocol side, InspIRCd implements all ratified IRCv3 specifications and WHOX, keeping it compatible with modern IRC clients and bouncers.$q$, $q$Performance-oriented features such as Linux epoll and FreeBSD kqueue support allow a single InspIRCd instance to handle a very large number of simultaneous connections efficiently, which is why it is a common choice for mid-size to large community and gaming-adjacent IRC networks that need to scale beyond a few hundred concurrent users.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$InspIRCd is entirely free and open source under the GPLv2 license, with no paid tiers, subscriptions, or usage limits imposed by the project itself. Because it is self-hosted server software rather than a SaaS product, the only real cost is the infrastructure an operator chooses to run it on, whether that is a small home server, a VPS, or a dedicated box for a large public network.$q$, $q$There is no official commercial support contract sold by the InspIRCd project; operators rely on public documentation, the community IRC channel, and the GitHub issue tracker for help, which is typical of volunteer-maintained open-source infrastructure software rather than venture-backed SaaS products.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3277e798-0260-4d98-ba6f-cc95e7dc5b48', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
