INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Unlimited sending accounts$q$, $q$Connect an unlimited number of email inboxes on every paid plan with no per-seat mailbox pricing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Automated email warmup$q$, $q$Built-in warmup network gradually builds sender reputation to improve inbox placement before and during campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Unibox unified inbox$q$, $q$Manage replies across every connected account and active campaign from a single shared inbox view.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$AI Sales Agent and AI Reply Agent$q$, $q$AI tools personalize outbound messaging and can triage or draft responses to incoming replies automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$B2B lead database$q$, $q$Instantly Credits (formerly SuperSearch) provides access to a reported 450 million-plus contact database for sourcing leads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Campaign analytics and A/B testing$q$, $q$Track open, reply, and bounce rates and split-test subject lines and sequences across campaigns.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Built-in CRM add-on$q$, $q$Optional CRM module tracks deals and pipeline generated directly from outbound email replies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Inbox rotation and deliverability tools$q$, $q$Automatically rotates sends across connected inboxes to stay under daily sending limits and reduce spam flags.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Unlimited connected email accounts with no per-seat pricing on any plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Effective automated warmup that many users report meaningfully improves inbox placement$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Fast, intuitive setup even for teams with no prior cold email experience$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Strong G2 reputation with thousands of largely positive verified reviews$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Bundled lead database and CRM reduce the need for separate outbound tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Deliverability results can be inconsistent and hard to diagnose even with warmup enabled$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Lead database data quality is reported as uneven, with stale or mismatched contacts at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Real-world monthly cost rises quickly once Leads and CRM modules are added to base Outreach pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Some users report done-for-you domain setups arriving with weak sender reputation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$No permanent free plan, only a limited free trial period$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Is Instantly free to use?$q$, $q$Instantly does not offer a permanent free plan; it offers a limited free trial, with paid Outreach plans starting at 47 dollars per month (about 37.60 dollars per month billed annually).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Who founded Instantly?$q$, $q$Instantly was founded in 2021 by Nils Schneider, Raul Kaevand, Reio Suun, and Sumit Kumar, and the company remains fully bootstrapped with no outside investor funding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Does Instantly limit the number of email accounts I can connect?$q$, $q$No. Every paid Instantly plan allows unlimited connected email sending accounts and unlimited automated warmup, with pricing instead based on monthly email volume and uploaded contacts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$What is Instantly's lead database?$q$, $q$Instantly Credits (formerly called SuperSearch) is a built-in B2B contact database, reportedly covering more than 450 million contacts, sold as a separate module alongside the core Outreach product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$How much does Instantly really cost with all features?$q$, $q$While base Outreach plans start around 47 dollars per month, adding the Leads database and CRM modules typically brings real-world monthly spend to roughly 150 to 400 dollars depending on volume and add-ons.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$What are the main alternatives to Instantly?$q$, $q$Common alternatives include Smartlead, Apollo.io, Lemlist, Woodpecker, and Salesforge, which compete on similar cold email deliverability, warmup, and outbound sequencing features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$B2B cold email outreach at scale$q$, $q$Sales teams run high-volume outbound campaigns across many connected inboxes while maintaining deliverability.$q$, $q$SDR and business development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Lead generation agencies$q$, $q$Agencies manage cold outreach for multiple clients using shared lead sourcing, warmup, and reporting infrastructure.$q$, $q$Lead-gen and growth marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Founder-led sales outbound$q$, $q$Early-stage founders run their own outbound campaigns to book sales meetings without hiring a dedicated SDR team.$q$, $q$Startup founders and small sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Growth$q$, $q$$47/month ($37.60/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["5,000 emails per month","1,000 uploaded contacts","Unlimited email accounts and warmup","Chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Hypergrowth$q$, $q$$97/month ($77.60/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["100,000 emails per month","25,000 uploaded contacts","AI Reply Agent","Premium live support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Light Speed$q$, $q$$358/month ($286.30/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["500,000+ emails per month","100,000+ uploaded contacts","SISR high-volume sending infrastructure"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Private deliverability network","Dedicated account manager","Shared Slack support channel","Custom volume above 500,000 emails/month"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Instantly was founded in 2021 by Nils Schneider, Raul Kaevand, Reio Suun, and Sumit Kumar, a team that met largely through online indie-hacker and cold-outreach communities rather than a traditional startup accelerator. Built entirely bootstrapped with no outside funding, the company grew from zero to millions in annual recurring revenue within its first year by focusing on the pain points of cold email deliverability that agencies and SDR teams face at scale.$q$, $q$The platform is a cloud-based cold email and sales engagement tool that connects to existing email inboxes rather than requiring a dedicated sending infrastructure, then layers automated warmup, multi-inbox rotation, and reply management on top to keep large-volume outbound campaigns out of spam folders.$q$, $q$Instantly has since expanded beyond pure email sending into a broader outbound stack, adding a B2B lead database (Instantly Credits, formerly SuperSearch), an AI Sales Agent and AI Reply Agent, and a lightweight CRM, positioning itself as an end-to-end outbound platform rather than a single-purpose email tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core differentiator is unlimited email account connections and unlimited automated warmup on every paid plan, with no per-seat pricing for mailboxes, which lets teams spread sending volume across many inboxes to stay under Gmail and Outlook daily sending caps while a single subscription covers the whole stack.$q$, $q$Unibox consolidates replies from every connected inbox and active campaign into one shared view, while the AI Reply Agent can triage and draft responses automatically, and the AI Sales Agent can personalize outbound messaging at scale using lead and company data.$q$, $q$Beyond sending, Instantly bundles a B2B contact database with access to a reported 450 million-plus leads, campaign-level analytics and A/B testing, and an add-on CRM for tracking deals generated from outbound replies, so growing teams can consolidate sourcing, sending, and pipeline management in one subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Instantly uses a modular pricing model built around three core subscriptions -- Outreach (email sending), Instantly Credits (the lead database), and CRM -- plus optional add-ons for Website Visitors, Inbox Placement testing, done-for-you account setup, and pre-warmed accounts. Standalone Outreach plans run from Growth at 47 dollars per month (5,000 emails, 1,000 contacts) up to Light Speed at 358 dollars per month (500,000-plus emails, 100,000-plus contacts), with roughly 20 percent savings on annual billing, and a custom Enterprise tier above that.$q$, $q$Because Leads and CRM are billed separately starting around 47 dollars per month each, teams that need the full outbound stack should expect real-world costs well above the advertised entry price -- commonly cited in the 150 to 400 dollar per month range once lead sourcing and CRM are added -- which is an important consideration when comparing Instantly's headline pricing to all-in-one competitors.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83d74d9a-40c7-43db-b149-f6f2fdadf0e5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
