INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Drag-and-drop page builder$q$, $q$No-code visual editor with reusable blocks and hundreds of templates for building landing pages without developer help.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Server-side A/B testing$q$, $q$Runs split tests on the server to avoid page flicker, with hypothesis tracking and full experimentation history.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$AdMap$q$, $q$Visually maps ad campaigns to their corresponding landing pages for easier campaign-to-page management.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Dynamic text replacement$q$, $q$Automatically personalizes on-page copy based on the visitor's referring ad, keyword, or campaign.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$AI content generation$q$, $q$AI-assisted tools help draft landing page copy and suggest experiment variations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Heatmaps and analytics$q$, $q$Visualize visitor click and scroll behavior alongside GA4 custom event tracking to inform page changes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Programmatic Collections$q$, $q$Generate many similar landing page variants from a shared template for large-scale campaigns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Enterprise SSO and security$q$, $q$Convert plan adds SSO via Okta, PingOne, OneLogin, Azure, and Google, plus audit logs and a 99.9% uptime SLA.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Deep post-click optimization tools beyond basic page building, including AdMap and dynamic text replacement$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Server-side A/B testing avoids the flicker common in client-side testing tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Large library of professionally designed, conversion-focused templates$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Responsive, knowledgeable customer support according to reviewers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Strong native integrations with major marketing and sales platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$No permanent free plan, only a 14-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Pricing is high relative to competitors, especially for small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$A/B testing is locked behind the more expensive Optimize plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Visitor caps on each tier mean growing traffic can force a plan upgrade$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Mobile layout editing and heatmap depth trail some newer competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Does Instapage have a free plan?$q$, $q$No. Instapage offers only a 14-day free trial; the entry-level Create plan starts at 99 dollars per month (79 dollars per month billed annually).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Who owns Instapage now?$q$, $q$Instapage was acquired by airSlate in October 2023 and now operates as part of airSlate's broader business-process and document workflow product suite.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Does Instapage include A/B testing on every plan?$q$, $q$No. A/B testing, heatmaps, and personalization tools are only available starting on the Optimize plan; the entry-level Create plan does not include them.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$What is AdMap in Instapage?$q$, $q$AdMap is a visualization tool that connects specific ad campaigns and creative directly to the landing pages they drive traffic to, helping marketers manage campaign-to-page relationships at scale.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$What are the main Instapage alternatives?$q$, $q$The closest competitors are Unbounce, Leadpages, Landingi, ClickFunnels, and Webflow, each offering different tradeoffs between price, conversion tooling, and general website-building flexibility.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Who founded Instapage?$q$, $q$Instapage was founded in 2012 by Tyson Quick, who built the platform to help performance marketers reduce wasted ad spend from poorly matched landing pages.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Paid advertising campaign pages$q$, $q$Marketing teams build dedicated, message-matched landing pages for individual Google Ads or Meta ad campaigns.$q$, $q$Performance marketers and paid media managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Agency client landing pages$q$, $q$Agencies build and A/B test landing pages across multiple client accounts from one collaborative workspace.$q$, $q$Digital marketing and paid media agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Enterprise conversion rate optimization$q$, $q$Larger marketing organizations run structured, server-side A/B testing programs with SSO and audit-logged governance.$q$, $q$Enterprise demand generation and CRO teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Create$q$, $q$$99/month ($79/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 15,000 unique monthly visitors","Drag-and-drop builder with reusable blocks","AI content generation","Popups and sticky bars","10 team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Optimize$q$, $q$$199-$299/month ($159-$239/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["30,000-50,000 unique monthly visitors","Server-side A/B testing","Heatmaps and dynamic text replacement","AdMap and AI-powered experiments"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$Convert$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Enterprise SSO (Okta, PingOne, OneLogin, Azure, Google)","Audit logs","99.9% uptime SLA","Dedicated customer success manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Instapage was founded in 2012 by Tyson Quick to solve a specific performance-marketing problem: paid traffic sent to generic website pages converts far worse than traffic sent to a landing page built specifically for that ad and audience. The company built its platform around that insight, raising a 15 million dollar Series A led by Morgan Stanley Expansion Capital in 2018 and growing into one of the more established names in dedicated landing page software.$q$, $q$In October 2023, Instapage was acquired by airSlate, a document workflow automation company, which now owns and operates the product as part of its broader business-process suite rather than as a fully independent standalone company.$q$, $q$The platform is positioned specifically for post-click optimization -- what happens after someone clicks an ad -- rather than as a general website builder, which is why its feature set leans heavily toward experimentation, personalization, and analytics rather than broad content management functionality.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core builder is a drag-and-drop, no-code editor with reusable blocks, hundreds of professionally designed templates, and real-time visual collaboration, letting marketing teams launch new landing pages without engineering support. Programmatic 'Collections' allow marketers to generate many similar landing page variants (for example, per-city or per-campaign pages) from a shared template.$q$, $q$Instapage's differentiated strength is post-click optimization: server-side A/B testing avoids the visual flicker common in client-side testing tools, while AdMap visually connects specific ad creative to the landing pages it drives traffic to, and dynamic text replacement automatically swaps page copy based on the visitor's originating ad or search query for tighter message match.$q$, $q$AI is woven into both content creation and experimentation -- AI content generation helps draft page copy, while AI-powered experiments suggest test variations -- and the platform integrates natively with Google Analytics, Salesforce, HubSpot, Marketo, WordPress, Drupal, and Zapier, so page performance data flows into a team's existing marketing and sales stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Instapage has no permanent free plan, offering only a 14-day free trial before requiring a paid subscription. The entry-level Create plan costs 99 dollars per month (79 dollars per month billed annually) for up to 15,000 unique monthly visitors and includes the full builder, AI content tools, popups, and unlimited published pages and conversions, but excludes A/B testing.$q$, $q$A/B testing, heatmaps, and personalization tools are reserved for the Optimize plan, which starts at 199 dollars per month (159 dollars per month billed annually) for 30,000 visitors and scales to 299 dollars per month for 50,000 visitors. The top-tier Convert plan is custom-quoted for enterprise customers who need SSO, audit logging, a 99.9 percent uptime SLA, and dedicated support, and traffic overages on lower tiers are a common reason customers cite for needing to upgrade.$q$]::text[], 2);
