INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45bcdd12-fc73-4e69-a6ec-4961fd076322', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Uptime monitoring$q$, $q$Configurable monitors check service and API uptime at intervals as fast as 30 seconds on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Public and private status pages$q$, $q$Publish public status pages for customers or authenticated private pages for internal and restricted audiences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Multi-channel incident alerts$q$, $q$Notify subscribers and on-call team members via email, SMS, or phone call depending on plan tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Flat-fee pricing$q$, $q$Charges a single flat monthly fee per tier regardless of subscriber count, unlike many per-subscriber competitors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Custom branding and design$q$, $q$Modern, fast-loading page editor supports custom domains, branding, and layout components.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$On-call member routing$q$, $q$Route incident notifications to designated on-call team members for faster response.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$SAML SSO and SCIM$q$, $q$Business and Enterprise tiers add enterprise identity management for larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Scheduled maintenance windows$q$, $q$Communicate planned maintenance to subscribers in advance through the same status page interface.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Generous free tier with real functionality, not just a limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Flat-fee pricing that doesn't scale with subscriber or customer growth$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Fast, modern page design praised consistently by reviewers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Founder-led support known for responsiveness given the team's small size$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Simple setup that doesn't require dedicated IT or DevOps resources$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Large pricing jump from Pro ($20/month) to Business ($300/month) with no intermediate tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Private status pages and SAML SSO are locked behind the expensive Business plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Small team size means support response times can occasionally lag during high demand$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Interface can feel clunky for batch edits across many monitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Fewer deep incident-management workflow features than larger enterprise-focused competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Is Instatus free?$q$, $q$Yes. Instatus offers a free Starter plan with 15 monitors, email alerts, and up to 200 subscribers, with no time limit on usage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$How does Instatus pricing work?$q$, $q$Instatus charges a flat monthly fee per plan tier rather than charging based on the number of subscribers, which differs from many status page competitors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Who founded Instatus?$q$, $q$Instatus was founded in 2020 by Ali Salah, a solo developer from Egypt, and has remained bootstrapped and founder-led since launch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Does Instatus support private status pages?$q$, $q$Yes, but private, authenticated status pages are only available starting on the Business plan at 300 dollars per month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$What is the difference between Instatus Pro and Business plans?$q$, $q$Pro ($20/month) adds SMS alerts and higher monitor and subscriber limits over the free plan, while Business ($300/month) adds private status pages, SAML SSO, and much higher limits, representing a steep jump in price.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$What are the main alternatives to Instatus?$q$, $q$Common alternatives include Atlassian Statuspage, Better Stack, Hyperping, and incident.io, which compete on similar status page and incident communication functionality.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$SaaS and developer tool status pages$q$, $q$Software companies communicate uptime and incidents transparently to customers and integration partners.$q$, $q$SaaS companies and developer tool vendors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$IT and infrastructure incident communication$q$, $q$IT teams notify internal or external stakeholders automatically during outages and maintenance windows.$q$, $q$IT operations and infrastructure teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Community and gaming server status$q$, $q$Game server operators and Discord communities post real-time status updates for their services.$q$, $q$Game server operators and online communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Starter$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["15 monitors","2-minute checks","Email alerts","5 team members","200 subscribers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Pro$q$, $q$$20/month ($15/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["50 monitors","30-second checks","Email and SMS alerts","50 team members","5,000 subscribers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Business$q$, $q$$300/month ($225/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1,000 monitors","Private/authenticated status pages","SAML SSO","25,000 subscribers"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["SCIM directory sync","99.99% SLA","Multiple SSO connections","Custom contracts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Instatus was founded in 2020 by Ali Salah, a solo developer from Egypt who set out to build a faster, better-designed, and more affordably priced alternative to Atlassian's Statuspage.io. The product initially launched under a different name aimed at early-stage startups before Salah rebranded it as Instatus, after which it began gaining real customer traction and revenue.$q$, $q$The company has remained bootstrapped and founder-led throughout its growth, running publicly as an 'open startup' that shares revenue figures, and has grown into a small team while serving thousands of customers across the SaaS, developer tools, and IT services space.$q$, $q$Instatus is a cloud-based web application: teams configure uptime monitors for their own services and connect those monitors to a public or private status page that automatically reflects incidents, scheduled maintenance, and historical uptime, notifying subscribers through email, SMS, or phone calls depending on plan tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Instatus centers on speed and design: status pages are built to load quickly and update in near real time, with a modern editor that lets teams customize branding, layout, and components without needing design or development resources. Monitors check service uptime as frequently as every 30 seconds on paid plans and can trigger automatic incident creation.$q$, $q$Notifications scale by plan, from email-only alerts on the free tier to email, SMS, and phone-call alerts on Pro and Business, with on-call member support for routing incident notifications to the right team member. Higher tiers add private, authenticated status pages for internal or customer-restricted use, SAML SSO, and SCIM directory sync for enterprise identity management.$q$, $q$Unlike many status page competitors that charge based on the number of subscribers following updates or the number of user seats on the account, Instatus uses a flat per-tier fee regardless of subscriber count, which is one of its most cited advantages for growing companies that don't want their status page bill to scale with customer growth.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Instatus offers a genuinely usable free Starter plan with 15 monitors, 2-minute checks, email alerts, and up to 200 subscribers, making it accessible for small projects and early-stage products with no cost barrier. The Pro plan at 20 dollars per month (15 dollars per month billed annually) is aimed at growing teams that need faster 30-second checks, SMS alerts, and higher subscriber and monitor limits.$q$, $q$The jump to the Business plan at 300 dollars per month (225 dollars per month billed annually) is substantial, since it is the only tier that unlocks private status pages and SAML SSO, creating a pricing gap that is frequently flagged by reviewers and comparison sites as a drawback for mid-sized teams that need those specific features but don't yet need full enterprise scale. A custom Enterprise tier above Business adds SCIM, a 99.99 percent SLA, and multiple SSO connections for large organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f65f0d8b-0765-4d7b-b21b-657a547c6e7f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
