-- Enrichment marathon batch: Insomnia, InspIRCd, Instantly, Instapage, Instatus, Integrately, IntelliCode, Interakt

-- ── Insomnia ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Insomnia is an open-source, cross-platform API client for designing, testing, and debugging REST, GraphQL, WebSocket, SSE, and gRPC APIs.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$501-1000 employees (parent company Kong Inc.)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Insomnia Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Insomnia review 2026: see how Kong's open-source API client handles REST, GraphQL and gRPC testing, plus pricing tiers, features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Insomnia is an open-source, cross-platform desktop API client used by developers to design, debug, test, and document REST, GraphQL, WebSocket, Server-Sent Events, and gRPC APIs from a single interface. It was created in 2015 by independent developer Gregory Schier as a lightweight, design-focused alternative to heavier API tools, and it quickly gained a following in the developer community for its clean interface and native support for GraphQL alongside REST. On October 2, 2019, Insomnia was acquired by Kong Inc., the API gateway and service-connectivity company led by CEO and co-founder Augusto Marietti, which had itself grown out of the earlier Mashape API marketplace. Kong acquired Insomnia to broaden its open-source developer tooling and to serve as the client-side counterpart to Kong Studio and the Kong Konnect service connectivity platform; Kong committed to keeping Insomnia developed as an independent open-source project, and its source remains publicly maintained on GitHub under the Kong organization. Kong itself is headquartered in San Francisco, California, and has grown to roughly 700 employees across more than 25 global offices as of recent counts, after surpassing 100 million dollars in annual recurring revenue. Architecturally, Insomnia ships as a native Electron-based desktop application for macOS, Windows, and Linux, storing collections either locally, in Insomnia Cloud, or synced directly to a Git repository (Git Sync) for version-controlled, code-review-friendly API workflows. Core functionality includes a request builder with nested and environment-scoped variables, template tags and scripting hooks, an OpenAPI-aware design mode for authoring and linting specifications, built-in mock servers for simulating API responses during parallel frontend and backend development, and an Inso command-line interface that runs collections, tests, and specs inside CI/CD pipelines. Insomnia's plan structure is intentionally lean: the free Essentials plan includes unlimited local and cloud projects for all users, Git Sync for up to three users, the Inso CLI, unlimited collection runs and environments, 1,000 free mock-server requests per month, and end-to-end encryption for stored data. The Pro plan, at 12 dollars per user per month (with roughly 15 percent savings on annual billing), removes the Git Sync user cap, adds unlimited organizations, role-based access control, and 10,000 monthly mock requests. The Enterprise plan, self-serve up to 50 users at 45 dollars per user per month or custom-priced for larger teams, adds native Kong Konnect integration, enterprise SSO via SAML and OIDC, SCIM provisioning, mandated project storage locations, native secrets-vault integrations with AWS, GCP, HashiCorp, and Azure, unlimited mock requests, and optional Kong professional services. Insomnia targets individual developers, QA engineers, and cross-functional API teams that want a fast, uncluttered client without Postman's steeper learning curve or seat-heavy pricing; G2 reviewers rate it around 4.5 out of 5, consistently praising its simple interface, native Git-based collaboration, and strong GraphQL and gRPC support, while criticizing its comparatively thinner automated-testing and monitoring feature set, slower performance on very large collections, and a smaller third-party integration ecosystem. Its most direct competitor is Postman, the dominant API platform with a much larger user base, marketplace, and automation suite, followed by newer entrants such as Bruno (a fully offline, file-based, open-source client), Hoppscotch (a browser-based free client), and Thunder Client (a lightweight VS Code extension). Insomnia differentiates itself by combining a genuinely open-source core, native multi-protocol support in one client, and Git-native collaboration without requiring every collaborator to pay for a seat just to view shared collections.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '26e0091a-2dbf-4bce-9fd3-e6410e5065db';

