-- ── IntelliCode ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$IntelliCode was Microsoft's free AI-assisted IntelliSense extension for VS Code, offering ranked and whole-line code completions.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$10,001+ employees (Microsoft Corporation)$q$, company_size),
  headquarters = COALESCE($q$Redmond, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$IntelliCode Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$IntelliCode review 2026: how Microsoft's free AI-assisted IntelliSense extension for VS Code worked, its 2025 deprecation, and the best alternatives now.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Visual Studio IntelliCode was a free, Microsoft-built extension for Visual Studio Code (and a built-in feature of Visual Studio) that enhanced the standard IntelliSense autocomplete system with machine-learning-driven, context-aware code suggestions. Microsoft announced IntelliCode in 2017 as part of its broader push into AI-assisted developer tooling, using a combination of machine learning trained on high-quality, highly-rated public GitHub repositories and Programming By Examples techniques to detect repeated editing patterns in a developer's own code. Rather than replacing IntelliSense's completion list, IntelliCode reordered it: it moved the suggestions statistically most likely to be correct to the top of the list, marked them with a star icon, and, when confidence was high enough, displayed an inline grey-text preview of an entire predicted line that a developer could accept with Tab. In VS Code specifically, the extension (published by Microsoft under the identifier VisualStudioExptTeam.vscodeintellicode) supported whole-line completions, API usage examples sourced from over 100,000 public APIs on GitHub, and starred IntelliSense member ranking for Python, JavaScript, TypeScript (including JSX/TSX), and, through companion extensions, Java and C#; a key selling point was that the ML inference ran locally on the developer's own machine, so private source code was never sent to a cloud service for the completion feature to work. The extension proved extremely popular by installation count, reaching over 62 million installs on the VS Code Marketplace with an average rating around 4 out of 5 stars across roughly 100 reviews, making it one of the most widely installed AI-assisted coding tools of the pre-LLM-chatbot era. However, as generative, cloud-hosted large language models became the dominant paradigm for AI code assistance, Microsoft shifted its entire AI developer strategy toward GitHub Copilot, its subscription-based, cloud-inference coding assistant built on OpenAI's models. On November 12, 2025, Microsoft formally deprecated the IntelliCode suite for VS Code -- including the base IntelliCode extension, IntelliCode Completions, IntelliCode API Usage Examples, and IntelliCode for C# Dev Kit -- archiving the primary GitHub repository and disabling the starred-completion ranking feature as part of the VS Code 1.107 (November 2025) release. Microsoft's stated guidance going forward is for developers to use GitHub Copilot instead, which offers a limited free tier (around 2,000 completions per month) before requiring a paid subscription starting at 10 dollars per month for individuals or 19 dollars per month for GitHub Copilot Business. IntelliCode itself was never a standalone commercial product with its own pricing tiers; it was always free and bundled as part of Microsoft's developer tooling ecosystem, funded indirectly through Microsoft's broader Visual Studio and Azure business rather than through direct extension revenue, and it was maintained by the Visual Studio Experimentation Team within Microsoft, a company with more than 220,000 employees headquartered in Redmond, Washington. Historically, IntelliCode's target audience was any VS Code or Visual Studio user who wanted smarter autocomplete without paying for or sending code to an external AI service -- a meaningfully different value proposition from Copilot's always-cloud, chat-and-agent-oriented model. Its closest historical competitors were Tabnine (which offered both local and cloud-based AI completion with a similar privacy-conscious pitch), Kite (a now-shut-down AI autocomplete tool), and later, GitHub Copilot itself, which effectively absorbed IntelliCode's user base after the 2025 deprecation. For teams and individual developers evaluating tools today, IntelliCode is best understood as a discontinued, legacy extension: it may still be installable and technically functional in older VS Code versions, but it receives no further updates, its starred-ranking backend has been disabled, and Microsoft's own documentation now directs users toward GitHub Copilot for AI-assisted coding going forward.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c2004859-32f9-4c73-b57e-50e85e1d4f75';

