-- ── Interakt ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Interakt is a WhatsApp Business API and commerce platform for customer engagement, marketing campaigns and support, built by Haptik.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Mumbai, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Interakt Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Interakt review 2026: see how this Jio Haptik-backed WhatsApp Business API platform handles campaigns, chatbots and commerce, plus pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Interakt is a WhatsApp Business API and customer engagement platform, based in Mumbai, India, that helps businesses run marketing campaigns, manage customer support conversations, and sell products directly through WhatsApp, with expanded support for Instagram DMs. It was founded in 2020 and is led by CEO Aakrit Vaish; the company is owned by Haptik, the conversational AI company that Vaish also leads, which is itself majority-owned by Reliance Jio (part of Reliance Industries), giving Interakt unusually deep financial backing for an Indian SaaS startup without needing traditional venture funding rounds of its own. Interakt raised early grant funding shortly after incorporation in September 2020, and its growth has since been funded primarily through its parent companies rather than independent institutional rounds. As of recent reporting, Interakt serves more than 50,000 businesses, reported annual revenue of approximately 232 crore rupees (roughly 28 million US dollars) for the fiscal year ending March 2025, and employs around 200 people. The company is headquartered at Peninsula Business Park in Lower Parel, Mumbai. Functionally, Interakt is a cloud-based SaaS platform built on top of the official WhatsApp Business Platform API (formerly WhatsApp Business API), giving businesses a compliant, scalable way to send marketing broadcasts, automated notifications, and support messages at volumes and with rich media formats that personal WhatsApp Business app accounts cannot handle. Its feature set includes a shared team inbox where multiple agents can manage WhatsApp conversations from one dashboard, a no-code chatbot builder ranging from simple linear flows to advanced branching automation, broadcast campaign tools with audience segmentation, e-commerce integrations (including Shopify and WooCommerce) for cart-recovery and order-update messaging, webhook and API access for custom integrations, and, more recently, AI-powered WhatsApp agents for sales, lead qualification, and support automation sold as an add-on. Interakt's pricing follows a tiered freemium model: the free Starter plan covers Instagram-only messaging with owner-only agent roles and basic campaign and inbox features; the Growth plan costs 55 dollars per month plus taxes and unlocks WhatsApp plus Instagram channels, unlimited agents across all roles, advanced campaigns, and the chatbot builder; the Advanced plan costs 69 dollars per month plus taxes and adds advanced chatbot flows, auto-assignment, webhooks, campaign fallback logic, and outbound calling features; and a custom-priced Enterprise plan removes limits entirely, adds a dedicated account manager, includes the RCS messaging channel, and removes markup charges on WhatsApp conversation fees. Separately, Interakt sells a Sales CRM module (starting around 2,499 rupees, roughly 30 US dollars, per month for 5 sales agents) and a WhatsApp AI Agents add-on (around 74.99 US dollars per month for three specialized agents, with a small free message allowance and per-message overage pricing). On top of subscription fees, customers also pay Meta's per-conversation WhatsApp messaging costs directly, which for India-based accounts range from roughly 0.13 to 0.96 rupees per conversation depending on category (marketing, utility, authentication, or free service messages), and these conversation costs can significantly exceed the subscription price at high message volumes. Interakt's target audience is primarily India-based direct-to-consumer (D2C) e-commerce brands and small-to-mid-sized businesses that need affordable, compliant WhatsApp messaging at scale without managing the Meta Business API integration themselves. On G2, Interakt holds roughly a 4.5 out of 5 rating from about 60 reviews, with users praising its affordability, ease of setup, and e-commerce-focused automation, while reviewers criticize its comparatively complex dashboard, email-only support with slow response times, and Trustpilot ratings that lag well behind its G2 score. Its principal competitors are WATI, AiSensy, Gupshup, and Twilio (for more custom/enterprise integrations), with Interakt differentiating primarily through its Jio Haptik ownership and financial stability, deep e-commerce platform integrations, and India-first pricing and support model.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '993a2b5b-ee72-498b-b5f1-82135cc21b11';

